import { Injectable } from '@angular/core';
import { Subject, Observable } from 'rxjs';

export interface Notification {
  id: number;
  message: string;
  type: 'success' | 'info' | 'warning' | 'error';
  timeout?: number;
}

@Injectable({
  providedIn: 'root'
})
export class NotificationService {
  private notificationSubject = new Subject<Notification>();
  private removeSubject = new Subject<number>();

  notifications$ = this.notificationSubject.asObservable();
  remove$ = this.removeSubject.asObservable();

  private counter = 0;

  constructor() { }

  show(message: string, type: 'success' | 'info' | 'warning' | 'error' = 'info', timeout: number = 3000): number {
    const id = this.counter++;

    this.notificationSubject.next({
      id,
      message,
      type,
      timeout
    });

    return id;
  }

  remove(id: number): void {
    this.removeSubject.next(id);
  }

  // Convenience methods
  success(message: string, timeout?: number): number {
    return this.show(message, 'success', timeout);
  }

  info(message: string, timeout?: number): number {
    return this.show(message, 'info', timeout);
  }

  warning(message: string, timeout?: number): number {
    return this.show(message, 'warning', timeout);
  }

  error(message: string, timeout?: number): number {
    return this.show(message, 'error', timeout);
  }
}
